#nullable enable // autogenerated  
  
using System.Xml;  
using MVZ2.IO;  
using MVZ2Logic.Games;  
using PVZEngine;  
  
namespace MVZ2.Metas  
{  
    public class ModelOverride  
    {  
        public NamespaceID? Path { get; set; }  
        public XMLConditionList? Conditions { get; set; }  
  
        public bool IsActive(IGlobalSaveData save)  
        {  
            if (Conditions == null || Conditions.Conditions.Length == 0)  
                return false;  
            return Conditions.MeetsConditions(save);  
        }  
  
        public static ModelOverride? FromXmlNode(XmlNode node, string defaultNsp)  
        {  
            var path = node.GetAttributeNamespaceID("path", defaultNsp);  
            if (!NamespaceID.IsValid(path))  
                return null;  
  
            XMLConditionList? conditions = null;  
            var conditionsNode = node["conditions"];  
            if (conditionsNode != null)  
            {  
                conditions = XMLConditionList.FromXmlNode(conditionsNode, defaultNsp);  
            }  
  
            return new ModelOverride  
            {  
                Path = path,  
                Conditions = conditions,  
            };  
        }  
    }  
}